const isAlive = (cell: Cell, cells: Cell[]): boolean =>
  cells.some(([x, y]) => x === cell[0] && y === cell[1]);

const deadNeighbors = (cells: Cell[]): Cell[] => {
  const result: Cell[] = [];
  for (const [x, y] of cells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        const candidate: Cell = [x + dx, y + dy];
        if (!isAlive(candidate, cells) && !isAlive(candidate, result)) {
          result.push(candidate);
        }
      }
    }
  }
  return result;
};

export const nextGeneration = (cells: Cell[]): Cell[] => {
  const survivors = cells.filter((cell) =>
    survives(countLiveNeighbors(cell, cells))
  );
  const births = deadNeighbors(cells).filter(
    (cell) => countLiveNeighbors(cell, cells) === 3
  );
  return [...survivors, ...births];
};
